91:     /**
92:      * @param {Frame} frame
93:      */
94:     async browse(frame) {
95:         if (frame.options.post_id) {
96:             if (frame.options.filter) {
97:                 frame.options.mongoTransformer = function (query) {
98:                     return {
99:                         $and: [
100:                             {
101:                                 post_id: frame.options.post_id
102:                             },
103:                             query
104:                         ]
105:                     };
106:                 };
107:             } else {
108:                 frame.options.filter = `post_id:${frame.options.post_id}`;
109:             }
110:         }
111: 
112:         return await this.service.getComments(frame.options);
113:     }
