121:                             {
122:                                 post_id: frame.options.post_id
123:                             },
124:                             query
125:                         ]
126:                     };
127:                 };
128:             } else {
129:                 frame.options.filter = `post_id:${frame.options.post_id}`;
130:             }
131:         }
132: 
133:         frame.options.isAdmin = true;
134:         // Admin routes in Comments-UI lack member context due to cross-domain constraints (CORS), which prevents
135:         // credentials from being passed. This causes issues like the inability to determine if a
136:         // logged-in admin (acting on behalf of a member) has already liked a comment.
137:         // To resolve this, we retrieve the `impersonate_member_uuid` from the request params and
138:         // explicitly set it in the context options as the acting member's ID.
139:         // Note: This approach is applied to several admin routes where member context is required.
140:         await this.#setImpersonationContext(frame.options);
141:         return await this.service.getAdminComments(frame.options);
