144:     /**
145:      * Browse all comments across the site (admin only, no post_id required)
146:      * Used for admin moderation page showing comments from all posts
147:      *
148:      * Controller responsibility: Parse frame into clean domain parameters.
149:      * The frame should not pass beyond this layer.
150:      *
151:      * @param {Frame} frame
152:      */
153:     async adminBrowseAll(frame) {
154:         // Query params can be strings or booleans depending on how the request is made
155:         const includeNestedParam = frame.options.include_nested;
156:         const includeNested = includeNestedParam !== 'false' && includeNestedParam !== false;
157: 
158:         // Extract count.reports from filter (it needs special handling as raw SQL)
159:         const {filter, reportCount, mongoTransformer} = this.#extractReportCountFilter(frame.options.filter);
160: 
161:         return await this.service.getAdminAllComments({
162:             includeNested,
163:             filter,
164:             mongoTransformer,
165:             reportCount,
