{"content":"1: const models = require('../../models');
2: const commentsService = require('../../services/comments');
3: const errors = require('@tryghost/errors');
4: function handleCacheHeaders(model, frame) {
5:     if (model) {
6:         const postId = model.get('post_id');
7:         const parentId = model.get('parent_id');
8:         const pathsToInvalidate = [
9:             postId ? `/api/members/comments/post/${postId}/` : null,
10:             parentId ? `/api/members/comments/${parentId}/replies/` : null
11:         ].filter(path => path !== null);
12:         frame.setHeader('X-Cache-Invalidate', pathsToInvalidate.join(', '));
13:     }
14: }
15: 
16: function validateCommentData(data) {
17:     if (!data.post_id && !data.parent_id) {
18:         throw new errors.ValidationError({
19:             message: 'Either post_id (for top-level comments) or parent_id (for replies) must be provided'
20:         });
21:     }
22: }
23: 
24: function validateCreatedAt(createdAt) {
25:     if (!createdAt) {
26:         return undefined;
27:     }
28:     
29:     // Only accept string or Date objects, reject other types like numbers
30:     if (typeof createdAt !== 'string' && !(createdAt instanceof Date)) {
31:         return undefined;
32:     }
33:     
34:     const date = new Date(createdAt);
35:     // Check if the date is valid and not in the future
36:     if (!isNaN(date.getTime()) && date <= new Date()) {
37:         return date;
38:     }
39:     
40:     return undefined;
41: }
42: 
43: /** @type {import('@tryghost/api-framework').Controller} */
44: const controller = {
45:     docName: 'comments',
46: 
47:     edit: {
48:         headers: {
49:             cacheInvalidate: false
50:         },
51:         options: [
52:             'id'
53:         ],
54:         validation: {
55:             options: {
56:                 id: {
57:                     required: true
58:                 }
59:             }
60:         },
61:         permissions: true,
62:         async query(frame) {
63:             const result = await models.Comment.edit({
64:                 id: frame.data.comments[0].id,
65:                 status: frame.data.comments[0].status
66:             }, frame.options);
67: 
68:             handleCacheHeaders(result, frame);
69: 
70:             return result;
71:         }
72:     },
73:     browse: {
74:         headers: {
75:             cacheInvalidate: false
76:         },
77:         options: [
78:             'post_id',
79:             'include',
80:             'page',
81:             'limit',
82:             'fields',
83:             'filter',
84:             'order',
85:             'debug',
86:             'impersonate_member_uuid'
87:         ],
88:         validation: {
89:             options: {
90:                 post_id: {
91:                     required: true
92:                 }
93:             }
94:         },
95:         permissions: true,
96:         async query(frame) {
97:             const result = await commentsService.controller.adminBrowse(frame);
98:             return result;
99:         }
100:     },
101:     browseAll: {
102:         headers: {
103:             cacheInvalidate: false
104:         },
105:         options: [
106:             'page',
107:             'limit',
108:             'filter',
109:             'order',
110:             'include_nested'
111:         ],
112:         validation: {},
113:         permissions: {
114:             method: 'browse'
115:         },
116:         async query(frame) {
117:             const result = await commentsService.controller.adminBrowseAll(frame);
118:             return result;
119:         }
120:     },
121:     add: {
122:         statusCode: 201,
123:         headers: {
124:             cacheInvalidate: false
125:         },
126:         options: [
127:             'include'
128:         ],
129:         validation: {
130:             options: {
131:                 include: {
132:                     values: ['post', 'member', 'replies', 'replies.member']
133:                 }
134:             },
135:             data: {
136:                 member_id: {
137:                     required: true
138:                 },
139:                 html: {
140:                     required: true
141:                 }
142:             }
143:         },
144:         permissions: true,
145:         async query(frame) {
146:             const data = frame.data.comments[0];
147:             
148:             validateCommentData(data);
149:             const validatedCreatedAt = validateCreatedAt(data.created_at);
150:             
151:             // Set internal context to prevent notifications
152:             if (!frame.options.context) {
153:                 frame.options.context = {};
154:             }
155:             frame.options.context.internal = true;
156:             
157:             const result = data.parent_id
158:                 ? await commentsService.api.replyToComment(
159:                     data.parent_id,
160:                     data.in_reply_to_id,
161:                     data.member_id,
162:                     data.html,
163:                     frame.options,
164:                     validatedCreatedAt
